import{_ as t,a,b as o,c as d,d as p,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dropbox Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/dropbox.md","filePath":"my/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"my/upload/dropbox.md"};function h(b,e,u,m,g,f){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="dropbox-channel-ထည့်သွင်းခြင်း" tabindex="-1">Dropbox Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#dropbox-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Dropbox Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>ဘာကြောင့်လိုလဲ</th></tr></thead><tbody><tr><td>Dropbox account</td><td>sign in ဝင်ရန်နှင့် app authorize လုပ်ရန်</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> နဲ့ <code>App Secret</code> generate လုပ်ရန်</td></tr><tr><td>သင့် ImgBed domain</td><td>OAuth redirect URI အတွက်</td></tr><tr><td>Dropbox storage ရရှိနိုင်မှု</td><td>file storage location အဖြစ်သုံးရန်</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-dropbox-app-ဖန်တီးပါ" tabindex="-1">Step 1: Dropbox App ဖန်တီးပါ <a class="header-anchor" href="#step-1-dropbox-app-ဖန်တီးပါ" aria-label="Permalink to &quot;Step 1: Dropbox App ဖန်တီးပါ&quot;">​</a></h3><ol><li>Dropbox App Console ကိုဖွင့်ပါ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>app အသစ်ဖန်တီးပါ။</li><li>access type အတွက်ရွေးပါ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>app ကိုမှတ်မိလွယ်တဲ့အမည်ပေးပါ၊ ဥပမာ <code>imgbed-app</code>။</li><li>app ဖန်တီးပြီးနောက် app details page ကိုဖွင့်ပါ။</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended။ ImgBed ရဲ့ file storage ပုံစံနဲ့ကိုက်ညီသည်။</td></tr><tr><td><code>Full Dropbox</code></td><td>မထောက်ခံပါ။ ImgBed က full-account access မလိုပါ။</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-redirect-uri-ထည့်ပါ" tabindex="-1">Step 2: Redirect URI ထည့်ပါ <a class="header-anchor" href="#step-2-redirect-uri-ထည့်ပါ" aria-label="Permalink to &quot;Step 2: Redirect URI ထည့်ပါ&quot;">​</a></h3><p>Dropbox app details page မှာ OAuth သို့မဟုတ် Redirect URI settings ကိုရှာပြီး ထည့်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>admin panel ကို domain တစ်ခုထက်ပိုပြီးသုံးလျှင် matching callback URL တစ်ခုချင်းစီထည့်ပါ။</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-app-permissions-configure-လုပ်ပါ" tabindex="-1">Step 3: App Permissions Configure လုပ်ပါ <a class="header-anchor" href="#step-3-app-permissions-configure-လုပ်ပါ" aria-label="Permalink to &quot;Step 3: App Permissions Configure လုပ်ပါ&quot;">​</a></h3><p><code>Permissions</code> tab ကိုဖွင့်ပြီး အနည်းဆုံး ဒီ scopes တွေ enable လုပ်ပါ:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>account နဲ့ quota information ဖတ်ရန်</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>path checks အတွက် file/folder metadata ဖတ်ရန်</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>folders ဖန်တီးရန်နှင့် metadata ရေးရန်</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>files upload လုပ်ရန်။ ဒီ scope မရှိလျှင် <code>required scope &#39;files.content.write&#39;</code> error ဖြစ်မည်။</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>download, preview, temporary file links အတွက်ခွင့်ပြုသည်</td></tr></tbody></table><p>scopes ရွေးပြီးနောက် page အောက်ခြေက <code>Submit</code> ကိုနှိပ်ပါ။</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>What To Do</th></tr></thead><tbody><tr><td>scopes ပြောင်းထားသည်</td><td>token authorization flow ကိုပြန် run လုပ်ပြီး <code>Refresh Token</code> အသစ်ယူပါ။</td></tr><tr><td>reauthorize မလုပ်ထား</td><td>token ဟောင်းက permissions အသစ်မရပါ၊ upload က fail ဖြစ်နေနိုင်သည်။</td></tr></tbody></table><h3 id="step-4-app-credentials-copy-လုပ်ပါ" tabindex="-1">Step 4: App Credentials Copy လုပ်ပါ <a class="header-anchor" href="#step-4-app-credentials-copy-လုပ်ပါ" aria-label="Permalink to &quot;Step 4: App Credentials Copy လုပ်ပါ&quot;">​</a></h3><p>Dropbox app page မှ ဒီ values နှစ်ခုကိုသိမ်းပါ:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-imgbed-မှာ-dropbox-channel-ဖြည့်ပါ" tabindex="-1">Step 5: ImgBed မှာ Dropbox Channel ဖြည့်ပါ <a class="header-anchor" href="#step-5-imgbed-မှာ-dropbox-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;Step 5: ImgBed မှာ Dropbox Channel ဖြည့်ပါ&quot;">​</a></h3><p>Upload Settings မှာ <code>Dropbox</code> ကိုရွေးပြီး:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>အခုခဏဗလာထားပါ</td></tr><tr><td>Root directory</td><td>Optional။ default က <code>imgbed</code>။</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-refresh-token-ရယူပါ" tabindex="-1">Step 6: Refresh Token ရယူပါ <a class="header-anchor" href="#step-6-refresh-token-ရယူပါ" aria-label="Permalink to &quot;Step 6: Refresh Token ရယူပါ&quot;">​</a></h3><ol><li>ImgBed မှာ <code>Get Token</code> ကိုနှိပ်ပါ။</li><li>connect လုပ်ချင်တဲ့ Dropbox account ထဲ sign in ဝင်ပါ။</li><li>authorization prompt ကို approve လုပ်ပါ။</li><li>callback page မှာ <code>Refresh Token</code> ပြပါမယ်။</li><li>အဲဒါကို copy လုပ်ပါ။</li><li>ImgBed ကိုပြန်သွားပြီး <code>Refresh Token</code> field ထဲ paste လုပ်ပါ။</li></ol><p><img src="'+p+'" alt="Copy token" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save ပြီးနောက် Dropbox channel ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel switch</td><td>channel ကို enable လုပ်လို့ရရပါမယ်။</td></tr><tr><td>Token saved</td><td>detail page မှာ <code>Refresh Token</code> သိမ်းထားကြောင်းပြရပါမယ်။</td></tr><tr><td>Upload test</td><td>test image က Dropbox app folder ထဲပေါ်လာရပါမယ်။</td></tr></tbody></table><p>quota limits enabled ဖြစ်လျှင် quota query ကိုနှိပ်ပါ။ query အောင်မြင်ပြီးနောက် channel card က used space, total space, last update time ကိုပြပါမယ်။</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed က configuration incomplete လို့ပြသည်</td><td><code>App Key</code>, <code>App Secret</code>, <code>Refresh Token</code> အားလုံးဖြည့်ထားလားစစ်ပါ။</td></tr><tr><td>Authorization အောင်မြင်ပေမယ့် <code>Refresh Token</code> မပေါ်</td><td><code>Get Token</code> ကိုပြန်နှိပ်ပြီး offline authorization flow သုံးနေလားစစ်ပါ။</td></tr><tr><td>Upload က <code>required scope &#39;files.content.write&#39;</code> နဲ့ fail ဖြစ်သည်</td><td><code>files.content.write</code> enable လုပ်ပါ၊ <code>Submit</code> နှိပ်ပါ၊ <code>Refresh Token</code> အသစ်ယူပါ။</td></tr><tr><td>Callback fail ဖြစ်သည်</td><td>redirect URI က <code>https://your-domain.com/api/oauth/dropbox/callback</code> ဖြစ်ကြောင်း confirm လုပ်ပါ။</td></tr><tr><td>Files မတွေ့</td><td>Dropbox app ကို <code>App folder</code> mode နဲ့ဖန်တီးထားလား confirm လုပ်ပါ။</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; app ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; App folder access ရွေးပါ</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback ထည့်ပါ</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write enable လုပ်ပါ</span></span>
<span class="line"><span>-&gt; လိုအပ်လျှင် files.content.read enable လုပ်ပါ</span></span>
<span class="line"><span>-&gt; Submit ကိုနှိပ်ပါ</span></span>
<span class="line"><span>-&gt; App Key နဲ့ App Secret copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed ထဲထည့်ပါ</span></span>
<span class="line"><span>-&gt; Get Token ကိုနှိပ်ပါ</span></span>
<span class="line"><span>-&gt; callback page မှ Refresh Token copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ paste လုပ်ပြီး save လုပ်ပါ</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const q=s(c,[["render",h]]);export{y as __pageData,q as default};
